import * as THREE from '../vendor/three.module.js';

export class ParticleSwarm {
    constructor(scene, count = 5000) {
        this.scene = scene;
        this.count = count;

        this.geometry = new THREE.BufferGeometry();
        this.positions = new Float32Array(this.count * 3);
        this.velocities = new Float32Array(this.count * 3);
        this.colors = new Float32Array(this.count * 3);
        this.sizes = new Float32Array(this.count);

        const color1 = new THREE.Color(0x38bdf8); // Cyan
        const color2 = new THREE.Color(0xa855f7); // Purple

        for (let i = 0; i < this.count; i++) {
            const i3 = i * 3;
            // Spawn in a sphere
            const r = 20 * Math.cbrt(Math.random());
            const theta = Math.random() * 2 * Math.PI;
            const phi = Math.acos(2 * Math.random() - 1);
            
            this.positions[i3] = r * Math.sin(phi) * Math.cos(theta);
            this.positions[i3 + 1] = r * Math.sin(phi) * Math.sin(theta);
            this.positions[i3 + 2] = r * Math.cos(phi);

            // Initial orbital velocity
            this.velocities[i3] = -this.positions[i3 + 2] * 0.05 + (Math.random() - 0.5);
            this.velocities[i3 + 1] = (Math.random() - 0.5) * 0.5;
            this.velocities[i3 + 2] = this.positions[i3] * 0.05 + (Math.random() - 0.5);

            // Interpolate colors
            const c = color1.clone().lerp(color2, Math.random());
            this.colors[i3] = c.r;
            this.colors[i3 + 1] = c.g;
            this.colors[i3 + 2] = c.b;

            this.sizes[i] = Math.random() * 2.0 + 0.5;
        }

        this.geometry.setAttribute('position', new THREE.BufferAttribute(this.positions, 3));
        this.geometry.setAttribute('color', new THREE.BufferAttribute(this.colors, 3));
        this.geometry.setAttribute('size', new THREE.BufferAttribute(this.sizes, 1));

        // Create a simple circular particle texture via canvas
        const canvas = document.createElement('canvas');
        canvas.width = 64;
        canvas.height = 64;
        const ctx = canvas.getContext('2d');
        const gradient = ctx.createRadialGradient(32, 32, 0, 32, 32, 32);
        gradient.addColorStop(0, 'rgba(255,255,255,1)');
        gradient.addColorStop(0.2, 'rgba(255,255,255,0.8)');
        gradient.addColorStop(0.6, 'rgba(255,255,255,0.2)');
        gradient.addColorStop(1, 'rgba(0,0,0,0)');
        ctx.fillStyle = gradient;
        ctx.fillRect(0, 0, 64, 64);
        const texture = new THREE.CanvasTexture(canvas);

        this.material = new THREE.ShaderMaterial({
            uniforms: {
                uTime: { value: 0 },
                uAudioLevel: { value: 0 },
                tSprite: { value: texture }
            },
            vertexShader: `
                uniform float uTime;
                uniform float uAudioLevel;
                attribute float size;
                attribute vec3 color;
                varying vec3 vColor;
                
                void main() {
                    vColor = color;
                    vec4 mvPosition = modelViewMatrix * vec4(position, 1.0);
                    // Particles pulse size with audio
                    float audioPulse = 1.0 + (uAudioLevel * 2.0);
                    gl_PointSize = size * audioPulse * (300.0 / -mvPosition.z);
                    gl_Position = projectionMatrix * mvPosition;
                }
            `,
            fragmentShader: `
                uniform sampler2D tSprite;
                varying vec3 vColor;
                void main() {
                    vec4 texColor = texture2D(tSprite, gl_PointCoord);
                    if (texColor.a < 0.1) discard;
                    gl_FragColor = vec4(vColor * texColor.rgb, texColor.a * 0.8);
                }
            `,
            transparent: true,
            blending: THREE.AdditiveBlending,
            depthWrite: false
        });

        this.mesh = new THREE.Points(this.geometry, this.material);
        this.scene.add(this.mesh);
    }

    update(deltaTime, audioLevel) {
        this.material.uniforms.uTime.value += deltaTime;
        this.material.uniforms.uAudioLevel.value = audioLevel;

        const positions = this.geometry.attributes.position.array;
        
        // Dynamic attraction force based on audio
        const gravity = 0.5 + (audioLevel * 5.0); 

        for (let i = 0; i < this.count; i++) {
            const i3 = i * 3;
            
            const px = positions[i3];
            const py = positions[i3 + 1];
            const pz = positions[i3 + 2];

            const distSq = px*px + py*py + pz*pz;
            const dist = Math.sqrt(distSq) + 0.1;

            // Swarm force towards center
            const fx = -(px / dist) * gravity;
            const fy = -(py / dist) * gravity;
            const fz = -(pz / dist) * gravity;

            // Chaos/scatter from loud beats
            const scatter = audioLevel > 0.6 ? (Math.random() - 0.5) * 2.0 : 0;

            this.velocities[i3] += (fx + scatter) * deltaTime;
            this.velocities[i3 + 1] += (fy + scatter) * deltaTime;
            this.velocities[i3 + 2] += (fz + scatter) * deltaTime;

            // Damping (friction)
            this.velocities[i3] *= 0.98;
            this.velocities[i3 + 1] *= 0.98;
            this.velocities[i3 + 2] *= 0.98;

            positions[i3] += this.velocities[i3] * deltaTime * 10;
            positions[i3 + 1] += this.velocities[i3 + 1] * deltaTime * 10;
            positions[i3 + 2] += this.velocities[i3 + 2] * deltaTime * 10;
        }

        this.geometry.attributes.position.needsUpdate = true;
        this.mesh.rotation.y += deltaTime * 0.2; // Slow global rotation
    }

    dispose() {
        this.scene.remove(this.mesh);
        this.geometry.dispose();
        this.material.dispose();
        this.material.uniforms.tSprite.value.dispose();
    }
}
